#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1 // halo width along one direction when advancing to the next iteration

#define M_SEED 9
int pyramid_height;

int rows, cols;
int* data;
int** wall;
int* result;

void init(int argc, char** argv) {
    if (argc == 4) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
        pyramid_height = atoi(argv[3]);
    } else {
        printf("Usage: dynproc row_len col_len pyramid_height\n");
        exit(0);
    }
    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
        wall[n] = data + cols * n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }
}

void fatal(char* s) {
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max)   ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? min : ((x > (max)) ? max : x)
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

void dynproc_kernel(int iteration, int* gpuWall, int* gpuSrc, int* gpuResults, int cols, int rows, int startStep, int border) {
    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blockCols = cols / small_block_cols + ((cols % small_block_cols == 0) ? 0 : 1);

    #pragma omp parallel for
    for (int bx = 0; bx < blockCols; bx++) {
        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;
        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            int W = tx - 1;
            int E = tx + 1;

            W = (W < validXmin) ? validXmin : W;
            E = (E > validXmax) ? validXmax : E;

            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            int prev[BLOCK_SIZE];
            int result[BLOCK_SIZE];

            if (IN_RANGE(xidx, 0, cols - 1)) {
                prev[tx] = gpuSrc[xidx];
            }

            bool computed = false;
            for (int i = 0; i < iteration; i++) {
                if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                    computed = true;
                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int index = cols * (startStep + i) + xidx;
                    result[tx] = shortest + gpuWall[index];
                }

                if (computed) {
                    prev[tx] = result[tx];
                }
            }

            if (computed) {
                gpuResults[xidx] = result[tx];
            }
        }
    }
}

int calc_path(int* gpuWall, int* gpuResult[2], int rows, int cols, int pyramid_height, int blockCols, int borderCols) {
    int src = 1, dst = 0;
    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;
        dynproc_kernel(MIN(pyramid_height, rows - t - 1), gpuWall, gpuResult[src], gpuResult[dst], cols, rows, t, borderCols);
    }
    return dst;
}

int main(int argc, char** argv) {
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int smallBlockCol = BLOCK_SIZE - (pyramid_height) * HALO * 2;
    int blockCols = cols / smallBlockCol + ((cols % smallBlockCol == 0) ? 0 : 1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n", pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int* gpuWall = new int[rows * cols - cols];
    int* gpuResult[2];
    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];

    for (int i = 0; i < cols; i++) {
        gpuResult[0][i] = data[i];
    }

    for (int i = 0; i < rows * cols - cols; i++) {
        gpuWall[i] = data[cols + i];
    }

    double start_time = omp_get_wtime();
    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, pyramid_height, blockCols, borderCols);
    double end_time = omp_get_wtime();

    for (int i = 0; i < cols; i++) {
        result[i] = gpuResult[final_ret][i];
    }

    delete[] gpuWall;
    delete[] gpuResult[0];
    delete[] gpuResult[1];

    delete[] data;
    delete[] wall;
    delete[] result;

    printf("timer: %f\n", end_time - start_time);

    return EXIT_SUCCESS;
}
